import{_ as c}from"./nyalra_kb-7135827b.js";import{_ as r}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as s,X as i,Y as _,Z as e,$ as t,a0 as a,a2 as m,a1 as d,C as o}from"./framework-a4c02b8f.js";const f={},g=e("figure",null,[e("img",{src:c,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/9d402248832426697904ca683c1ffa17.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>日复一日，我的书籍和电影收藏不断积压，直觉告诉我如果继续这样下去，这个局面将永无止境。于是，我决定整理现状，将积压的书籍、小说、漫画、电影、以及动画（特摄）等列成清单。我按照观看的优先顺序排列了它们，并准备了一张表格，以确保「在完成这些阅读和观看之前不再购买新的」。</p><p>然后，出现了什么情况呢？那些曾经期待着追的作品，如今却感觉像是一种「义务」或「作业」，一点兴趣都无法激起。到底是在欣赏我现在感兴趣的作品，还是只是为了填满清单而「消耗」自己，我对自己的不负责任感甚至产生了厌恶。我发现，一旦有了清单，填充它的愉悦感，甚至胜过了攻克游戏、完成收藏的快感。</p><p>「阅读或观看的优先顺位」是什么玩意啊！兴趣的优先顺位是一直在瞬息万变的。这是冲动。冲动战胜一切。「我现在就想看这部作品！！！」的瞬间，不管是工作，还是人际关系都变得无关紧要，能在第一时间享受作品才是最重要的。</p><p>书籍和电影不断堆积。多么美好的事情啊。我的兴趣和感性，随着它们的不断积累，就像搭建一座高塔一样，拥有着成长的空间。这真是多么奢侈而幸福的事情啊。追寻的越多，引起兴趣的对象也就越来越多。这个世界上还有许多我不知道的知识和刺激等待着我。真是一件令人激动的事情。这样一来，每一天都不会让我感到厌倦！</p><p>那么，就尽管买书籍和漫画吧。电影也一个接一个地加入清单吧！在需求出现的瞬间，我购买了能够尽可能顺畅访问相关作品的「环境」。毕竟冲动已经涌现了，如果因为阅读或观看的难度较高而使心情冷却，那实在是太可惜了。那些 Kindle 上没有，但将来想读的书籍，赶紧购买吧！不然等到你真的想读的时候再在网上下单，等到它送到家的时候，热情可能已经退却了。不必担心还有很多未读的东西。在引起兴趣的瞬间大胆购买，不断地积累生活的奖励吧！</p><p>在自己的兴趣重叠下，能够随时触及喜欢的事物的「环境」，这种巍峨的巴别塔屹立其中的喜悦。这确实是一种奢侈而充满人性的境遇。这就像是一座巴别塔，又好似是一座「巴别图书馆」。</p><p>怎么样？这一刹那，你是否突然感到桌上的书山让你感到自豪呢？如果你的桌子还是平整的话，那么现在就去书店，花上几千日元，任意购买书籍并堆放起来吧。突然间，当你看过去时，那里可能有着你尚未见过的奇幻和神秘等待着。你的知识好奇心仍然有着许多可以满足的空间。</p><p>……而且，如果不提升情绪，即使对某事很感兴趣，即使是喜欢的对象，也难以付诸实践。书架也不是无限的。对未来的过多期待也值得深思。</p><hr><p><img src="'+r+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/bae8b71ae16db1e94253886a419c12aa.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/c68c575b5be7e2303b6b514a6df33ffc.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/d69c291ea8fce315c2f0189f7e4179b8.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/095cced69d534635cc0b34d6ef5af6d5.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【R·多洛茜·怀因莱特】『THE BIG O』的女主角多洛茜的 figma。无论是 figma、Revoltech 还是黏土人，与10年前相比，它们的价格几乎翻了一番。过去，用2000日元就能买到可动的动漫人物模型的时代也是有的。</p></blockquote>',12);function u(y,v){const l=o("ExternalLinkIcon"),n=o("RouterLink");return s(),i("div",null,[_(" more "),g,e("p",null,[t("原文链接："),e("a",h,[t("第46回／本を積むことを恐れない"),a(l)])]),e("blockquote",null,[k,e("p",null,[a(n,{to:"/posts/Translate/nyalra_kb_45.html"},{default:m(()=>[t("【奈亚拉面壁自语】第45回｜试想真正的废人【230926】")]),_:1})])]),b])}const V=p(f,[["render",u],["__file","nyalra_kb_46.html.vue"]]);export{V as default};
